              <section className="flex flex-col gap-2">
                <form
                  onSubmit={(e) => submitForm(e, validateFullName, "fullname")}
                  className="flex flex-row gap-2">
                  <label htmlFor="fullname" className="sr-only">
                    Full name
                  </label>
                  <input
                    onChange={handelChange}
