    e.preventDefault();
    setLoading(true);
    setFormError(validateForm(formValue));
    if (Object.keys(validateForm(formValue)).length > 0) {
      setLoading(false);
      return null;
    } else {
      setSubmit(true);
      setFormValue({ email: "" });
      setLoading(false);
    }
